import{_ as a,o as i,c as t,ag as c}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"นามแฝง Security | Dotfiles (TH)","titleTemplate":":title","description":"คำสั่งความปลอดภัยแบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","frontmatter":{"title":"นามแฝง Security | Dotfiles","description":"คำสั่งความปลอดภัยแบบสั้น ภาพรวมสำหรับ Dotfiles v0.2.495 รองรับ macOS, Linux และ WSL ผ่าน Dotfiles","lang":"th-TH","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"นามแฝง Security | Dotfiles preview","canonical":"/th/aliases/security/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"นามแฝง Security","pageType":"docs","schemaType":"WebPage","permalink":"/th/aliases/security/"},"headers":[],"relativePath":"th/aliases/security/index.md","filePath":"th/aliases/security/index.md","lastUpdated":1773010926000}'),o={name:"th/aliases/security/index.md"};function l(d,e,s,r,n,u){return i(),t("div",null,[...e[0]||(e[0]=[c('<h1 id="นามแฝง-security" tabindex="-1">นามแฝง Security <a class="header-anchor" href="#นามแฝง-security" aria-label="Permalink to &quot;นามแฝง Security&quot;">​</a></h1><p>คำสั่งความปลอดภัยแบบสั้น</p><p>หน้านี้แนะนำกลุ่มนามแฝงหนึ่งกลุ่มและทางลัดคำสั่งทั่วไป อ่านหน้านี้ก่อนเพื่อทำความเข้าใจแบบแผนการตั้งชื่อ อินพุตที่คาดหวัง และรูปแบบการดำเนินการที่ปลอดภัย จากนั้นเปิดภาคผนวกอ้างอิงเพื่อดูรายการคำสั่งทั้งหมดและไวยากรณ์ที่แน่นอน นามแฝงเหล่านี้ลดการพิมพ์ซ้ำและรักษาพฤติกรรมเวิร์กโฟลว์ที่สม่ำเสมอบน macOS, Linux และ WSL</p><h2 id="เมื่อใดควรใช้" tabindex="-1">เมื่อใดควรใช้ <a class="header-anchor" href="#เมื่อใดควรใช้" aria-label="Permalink to &quot;เมื่อใดควรใช้&quot;">​</a></h2><p>ใช้หน้านี้ก่อนการทำงานเชลล์ประจำวันเมื่อคุณต้องการรูปแบบคำสั่งที่คาดเดาได้</p><h2 id="สิ่งที่รวมอยู่" tabindex="-1">สิ่งที่รวมอยู่ <a class="header-anchor" href="#สิ่งที่รวมอยู่" aria-label="Permalink to &quot;สิ่งที่รวมอยู่&quot;">​</a></h2><ul><li>นามแฝง: 98</li><li>ฟังก์ชันตัวช่วย: 61</li><li>ไฟล์ต้นฉบับ: 21</li></ul><h2 id="ตัวอย่างสั้น" tabindex="-1">ตัวอย่างสั้น <a class="header-anchor" href="#ตัวอย่างสั้น" aria-label="Permalink to &quot;ตัวอย่างสั้น&quot;">​</a></h2><ul><li><code>ccc</code> → <code>ccrypt -c</code></li><li><code>ccd</code> → <code>ccrypt -d</code></li><li><code>cce</code> → <code>ccrypt -e</code></li><li><code>check-locks</code> → <code>bash $script_path check</code></li><li><code>f2b</code> → <code>sudo fail2ban-client</code></li><li><code>f2br</code> → <code>sudo fail2ban-client reload</code></li><li><code>f2bs</code> → <code>sudo fail2ban-client status</code></li><li><code>f2bsa</code> → <code>sudo fail2ban-client status all</code></li><li><code>f2bssh</code> → <code>sudo fail2ban-client status sshd</code></li><li><code>fwahttp</code> → <code>sudo ufw allow http</code></li><li><code>fwahttps</code> → <code>sudo ufw allow https</code></li><li><code>fwaimaps</code> → <code>sudo ufw allow imaps</code></li></ul><h2 id="ขั้นตอนถัดไป" tabindex="-1">ขั้นตอนถัดไป <a class="header-anchor" href="#ขั้นตอนถัดไป" aria-label="Permalink to &quot;ขั้นตอนถัดไป&quot;">​</a></h2><p>เปิดรายการทั้งหมด:</p>',11)])])}const f=a(o,[["render",l]]);export{p as __pageData,f as default};
